import { mkdir, readdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import process from "node:process";

const GENERATED_BANNER =
  "<!-- Generated by scripts/agent-pipeline/sync-pipeline.mjs. Edit private/agent-pipeline/skills/*.md instead. -->";

function parseFrontmatter(source, filePath) {
  if (!source.startsWith("---\n")) {
    throw new Error(`Missing frontmatter in ${filePath}`);
  }

  const endIndex = source.indexOf("\n---\n", 4);
  if (endIndex === -1) {
    throw new Error(`Unterminated frontmatter in ${filePath}`);
  }

  const frontmatterBlock = source.slice(4, endIndex);
  const body = source.slice(endIndex + 5).trim();
  const metadata = {};

  for (const rawLine of frontmatterBlock.split("\n")) {
    const line = rawLine.trim();
    if (!line) continue;

    const separatorIndex = line.indexOf(":");
    if (separatorIndex === -1) {
      throw new Error(`Invalid frontmatter line "${rawLine}" in ${filePath}`);
    }

    const key = line.slice(0, separatorIndex).trim();
    const value = line.slice(separatorIndex + 1).trim();
    metadata[key] = stripQuotes(value);
  }

  for (const key of ["name", "description", "command_description", "cursor_description"]) {
    if (!metadata[key]) {
      throw new Error(`Missing "${key}" in ${filePath}`);
    }
  }

  return {
    metadata,
    body,
  };
}

function stripQuotes(value) {
  if (
    (value.startsWith('"') && value.endsWith('"')) ||
    (value.startsWith("'") && value.endsWith("'"))
  ) {
    return value.slice(1, -1);
  }

  return value;
}

function extractHeading(body, fallbackName) {
  const headingMatch = body.match(/^#\s+(.+)$/m);
  if (headingMatch) {
    return headingMatch[1].trim();
  }

  return fallbackName
    .split("-")
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function renderFrontmatter(entries) {
  return `---\n${entries.map(([key, value]) => `${key}: ${value}`).join("\n")}\n---`;
}

function renderCodexSkill({ name, description, body }) {
  return [
    renderFrontmatter([
      ["name", name],
      ["description", description],
    ]),
    "",
    GENERATED_BANNER,
    "",
    body.trim(),
    "",
  ].join("\n");
}

function renderClaudeSkill({ name, description, body }) {
  return [
    renderFrontmatter([
      ["name", name],
      ["description", description],
      ["language", "ja"],
    ]),
    "",
    GENERATED_BANNER,
    "",
    body.trim(),
    "",
  ].join("\n");
}

function renderCodexCommand({ commandDescription, name, body }) {
  return [
    renderFrontmatter([["description", commandDescription]]),
    "",
    "<instructions>",
    GENERATED_BANNER,
    `Use the canonical pipeline skill \`${name}\` as the source of truth.`,
    `If the user does not specify an output path, keep generated artifacts under \`docs/prd\`, \`docs/issues\`, or \`docs/rfc\` as appropriate.`,
    "",
    body.trim(),
    "</instructions>",
    "",
  ].join("\n");
}

function renderCursorRule({ cursorDescription, name, body }) {
  const promptTemplatePath = `private/agent-pipeline/cursor-prompts/${name}.md`;

  return [
    renderFrontmatter([
      ["description", cursorDescription],
      ["alwaysApply", "false"],
    ]),
    "",
    GENERATED_BANNER,
    "",
    `- Prompt template: \`${promptTemplatePath}\``,
    `- Mirror command name: \`/${name}\``,
    `- Follow the same workflow and output locations as the Codex and Claude variants.`,
    "",
    body.trim(),
    "",
  ].join("\n");
}

function renderCursorPrompt({ body }) {
  return [GENERATED_BANNER, "", body.trim(), ""].join("\n");
}

async function ensureParentDirectory(filePath) {
  await mkdir(path.dirname(filePath), { recursive: true });
}

async function writeGeneratedFile(filePath, contents) {
  await ensureParentDirectory(filePath);
  await writeFile(filePath, contents, "utf8");
}

async function loadSkillDefinitions(skillsDir) {
  const entries = await readdir(skillsDir, { withFileTypes: true });
  const skillFiles = entries
    .filter((entry) => entry.isFile() && entry.name.endsWith(".md"))
    .map((entry) => entry.name)
    .sort();

  const definitions = [];
  for (const fileName of skillFiles) {
    const filePath = path.join(skillsDir, fileName);
    const source = await readFile(filePath, "utf8");
    const { metadata, body } = parseFrontmatter(source, filePath);

    definitions.push({
      name: metadata.name,
      title: extractHeading(body, metadata.name),
      description: metadata.description,
      commandDescription: metadata.command_description,
      cursorDescription: metadata.cursor_description,
      body,
    });
  }

  return definitions;
}

export async function syncPipeline({ repoRoot = process.cwd() } = {}) {
  const skillsDir = path.join(repoRoot, "private/agent-pipeline/skills");
  const definitions = await loadSkillDefinitions(skillsDir);

  for (const definition of definitions) {
    await writeGeneratedFile(
      path.join(repoRoot, ".codex/skills", definition.name, "SKILL.md"),
      renderCodexSkill(definition),
    );
    await writeGeneratedFile(
      path.join(repoRoot, ".claude/skills", definition.name, "SKILL.md"),
      renderClaudeSkill(definition),
    );
    await writeGeneratedFile(
      path.join(repoRoot, ".codex/commands", `${definition.name}.md`),
      renderCodexCommand(definition),
    );
    await writeGeneratedFile(
      path.join(repoRoot, ".cursor/rules", `${definition.name}.mdc`),
      renderCursorRule(definition),
    );
    await writeGeneratedFile(
      path.join(repoRoot, "private/agent-pipeline/cursor-prompts", `${definition.name}.md`),
      renderCursorPrompt(definition),
    );
  }
}

if (import.meta.url === `file://${process.argv[1]}`) {
  await syncPipeline();
}
